<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body{font-family:Arial,Helvetica,sans-serif;margin:20px;}
  h1{margin-bottom:.5em;}
  form{margin-bottom:1.5em;}
  label{display:block;margin-top:.5em;}
  input[type="number"],input[type="date"],select,textarea{width:100%;padding:.4em;box-sizing:border-box;}
  button{margin-top:.8em;padding:.6em 1.2em;}
  #form-error{color:red;font-weight:bold;margin-top:.5em;}
  table{width:100%;border-collapse:collapse;margin-top:1em;}
  th,td{text-align:left;border-bottom:1px solid #ccc;padding:.4em;}
  .expense{background:#f9f9f9;}
  .exp-del{color:red;cursor:pointer;background:none;border:none;font-size:0.9em;}
  .summary{margin-top:1em;}
</style>
</head>
<body>

<h1>Expense Tracker</h1>

<form id="expense-form">
  <label>Amount:
    <input type="number" step="0.01" id="amount" required>
  </label>
  <label>Category:
    <select id="category">
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>Date:
    <input type="date" id="date" required>
  </label>
  <label>Note (optional):
    <textarea id="note"></textarea>
  </label>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<div class="filters">
  <label>Filter by Category:
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>From:
    <input type="date" id="filter-from">
  </label>
  <label>To:
    <input type="date" id="filter-to">
  </label>
</div>

<table>
  <thead>
    <tr><th>Amount</th><th>Category</th><th>Date</th><th></th></tr>
  </thead>
  <tbody id="expense-list"></tbody>
</table>

<div class="summary">
  <strong>Total: $<span id="total">0.00</span></strong>
</div>

<div class="category-totals">
  <p>Groceries: $<span class="cat-total" data-cat="groceries">0.00</span></p>
  <p>Transport: $<span class="cat-total" data-cat="transport">0.00</span></p>
  <p>Bills: $<span class="cat-total" data-cat="bills">0.00</span></p>
  <p>Fun: $<span class="cat-total" data-cat="fun">0.00</span></p>
</div>

<script>
(() => {
  const STORAGE_KEY = 'expenses';
  let expenses = [];

  // Load from localStorage
  function loadExpenses() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (data) expenses = JSON.parse(data);
  }

  // Save to localStorage
  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Render list
  function renderList() {
    const tbody = document.getElementById('expense-list');
    tbody.innerHTML = '';
    expenses.slice().sort((a,b)=>b.id-a.id).forEach(e=>{
      const tr = document.createElement('tr');
      tr.className = 'expense';
      tr.dataset.id = e.id;
      tr.dataset.cat = e.category;
      tr.dataset.date = e.date;
      tr.innerHTML = `
        <td>$${parseFloat(e.amount).toFixed(2)}</td>
        <td>${e.category}</td>
        <td>${e.date}</td>
        <td><button class="exp-del">Delete</button></td>`;
      tbody.appendChild(tr);
    });
  }

  // Apply filters
  function applyFilters() {
    const catSel = document.getElementById('filter-category').value;
    const fromDate = document.getElementById('filter-from').value;
    const toDate = document.getElementById('filter-to').value;

    document.querySelectorAll('.expense').forEach(row=>{
      let show = true;
      if (catSel !== 'all' && row.dataset.cat !== catSel) show = false;
      if (fromDate && row.dataset.date < fromDate) show = false;
      if (toDate && row.dataset.date > toDate) show = false;
      row.style.display = show ? '' : 'none';
    });
  }

  // Update totals
  function updateTotals() {
    let total = 0;
    const catSums = {groceries:0, transport:0, bills:0, fun:0};
    document.querySelectorAll('.expense').forEach(row=>{
      if (row.style.display !== 'none') {
        const amt = parseFloat(row.children[0].textContent.replace('$',''));
        total += amt;
        const cat = row.dataset.cat;
        catSums[cat] += amt;
      }
    });
    document.getElementById('total').textContent = total.toFixed(2);
    document.querySelectorAll('.cat-total').forEach(span=>{
      const cat = span.dataset.cat;
      span.textContent = catSums[cat].toFixed(2);
    });
  }

  // Add expense
  function addExpense(e){
    e.preventDefault();
    const amountInput = document.getElementById('amount');
    const category = document.getElementById('category').value;
    const date = document.getElementById('date').value;
    const note = document.getElementById('note').value.trim();

    const amtVal = parseFloat(amountInput.value);
    let error = '';
    if (!amtVal || isNaN(amtVal) || amtVal <= 0) {
      error = 'Amount must be a positive number.';
    } else if (!date) {
      error = 'Date is required.';
    }
    const errDiv = document.getElementById('form-error');
    if (error) {
      errDiv.textContent = error;
      return;
    }
    errDiv.textContent = '';
    const newExp = {id: Date.now()+Math.random(), amount: amtVal, category, date, note};
    expenses.push(newExp);
    saveExpenses();
    renderList();
    applyFilters();
    updateTotals();
    amountInput.value = '';
  }

  // Delete expense
  function deleteExpense(e){
    if (!e.target.classList.contains('exp-del')) return;
    const row = e.target.closest('.expense');
    const id = parseInt(row.dataset.id,10);
    expenses = expenses.filter(exp=>exp.id!==id);
    saveExpenses();
    renderList();
    applyFilters();
    updateTotals();
  }

  // Event listeners
  document.getElementById('expense-form').addEventListener('submit', addExpense);
  document.getElementById('expense-list').addEventListener('click', deleteExpense);
  ['filter-category','filter-from','filter-to'].forEach(id=>{
    document.getElementById(id).addEventListener('change', ()=>{
      applyFilters();
      updateTotals();
    });
  });

  // Initial load
  loadExpenses();
  renderList();
  applyFilters();
  updateTotals();
})();
</script>
</body>
</html>
